class Super {
    Super() {
        System.out.print('A');
    }

    Super(char x) {
        System.out.print(x);
    }
}

class Sub extends Super {
    Sub() {
        super();
        System.out.print('B');
    }

    Sub(char x) {
        this();
        System.out.print(x);
    }
}

public class Test {
    public static void main(String[] args) {
        Super s1 = new Super('C');
        Super s2 = new Sub('D');
    }
}

#include <stdio.h>

int a = 10;
int b = 20;
int c = 30;

void func(void)
{
    static int a = 100;
    int b = 200;

    a++;
    b++;

    c = a;
}

int main(void)
{
    func();
    func();

    printf("a = %d, b = %d, c = %d\n", a, b, c);

    return 0;
}
